def string_xor(a: str, b: str) -> str:
    """ Input are two strings a and b consisting only of 1s and 0s.
    Perform binary XOR on these inputs and return result also as a string.
    >>> string_xor('010', '110')
    '100'
    """
    if len(a)!= len(b):
        raise ValueError(f"Input strings must be of same length but given are a='{a}' and b='{b}'")
    result: List[str] = []
    for (i, j) in zip(a, b):
        if i!= j:
            result.append('1')
        else:
            result.append('0')
    return ''.join(result)
