    minSubArraySum([-1, -2, -3]) == -6
    """
    if not nums:
        return 0
    if len(nums) == 1:
        return nums[0]
    if len(nums) == 2:
        return max(nums)
    min_val = None
    min_val_so_far = None
    sum_so_far = None
    for n in nums:
        sum_so_far = n if sum_so_far is None else sum_so_far + n
        if min_val_so_far is None or sum_so_far < min_val_so_far:
            min_val_so_far = sum_so_far
        if min_val is None or sum_so_far < min_val:
            min_val = sum_so_far
        if sum_so_far < 0:
            sum_so_far = 0
    return min_val

